questions.question:
What does TypeScript infer as the return type of this function?

```ts
function add(a: number, b: number) {
  return a + b;
}
```

What is a default parameter?

```ts
function greet(name: string = 'World') {
  return `Hello, ${name}!`;
}
```

What does this code output?

```ts
function greet(name?: string): string {
  return `Hello, ${name ?? 'stranger'}!`;
}
console.log(greet());
```

What error does this produce?

```ts
function add(a: number, b: number): number {
  return a + b;
}
add(1, 2, 3);
```

What is the type of `fn` in this code?

```ts
type MathOp = (a: number, b: number) => number;
const fn: MathOp = (a, b) => a * b;
```

What does this function return?

```ts
function first<T>(arr: T[]): T | undefined {
  return arr[0];
}
console.log(first([]));
```

What is the difference between these two?

```ts
type A = (x: string) => void;
type B = { (x: string): void };
```

What does this rest parameter collect?

```ts
function log(message: string, ...tags: string[]) {
  console.log(message, tags);
}
log('hello', 'info', 'debug');
```

What does this code output?

```ts
const multiply = (a: number) => (b: number) => a * b;
const double = multiply(2);
console.log(double(5));
```

What does this code output?

```ts
function identity(x: number): number;
function identity(x: string): string;
function identity(x: any): any {
  return x;
}
console.log(identity('hello'));
```

What type does TypeScript infer for the parameter `x` in this callback?

```ts
const nums = [1, 2, 3];
nums.map(x => x * 2);
```

